// Validate body. Email is required. We do NOT leak whether the email
// maps to a user; the workflow always returns ok=true and only acts
// downstream when the lookup succeeds.
const body = $input.item.json.body || {};
const email = String(body.email || '').trim().toLowerCase();
if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
  return { json: { ok: false, status: 400, error: 'valid email required' } };
}
return { json: { ok: true, email } };

// Pass-through: stash the user lookup so we can read it after the
// rate-limit query overwrites $json in the next node.
const raw = $input.item.json;
const user = Array.isArray(raw) ? (raw[0] || null) : (raw && raw.id ? raw : null);
return { json: { user, email: $('Validate Email').item.json.email } };

// Combine user state + rate-limit state to decide whether to send.
// Always respond ok=true (do not leak existence or rate-limit window).
const stash = $('Stash User').item.json;
const user = stash.user;
const email = stash.email;

// Rate-limit query returns [] when no recent token, or [{id:...}] when there is one.
const recentRaw = $input.item.json;
const recent = Array.isArray(recentRaw) ? recentRaw : (recentRaw && recentRaw.id ? [recentRaw] : []);
const rateLimited = recent.length > 0;

let shouldSend = false;
let reason = '';
if (!user) { reason = 'no_user'; }
else if (user.is_active === false) { reason = 'suspended'; }
else if (user.email_verified === true) { reason = 'already_verified'; }
else if (rateLimited) { reason = 'rate_limited'; }
else { shouldSend = true; }

if (!shouldSend) {
  return { json: { ok: true, shouldSend: false, reason, email } };
}

// Mint a 32-byte base64url token, 24h expiry.
const crypto = require('crypto');
const token = crypto.randomBytes(32).toString('base64url');
const expires_at = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
return { json: { ok: true, shouldSend: true, email, token, expires_at, user_id: user.id } };

// Build the Postmark verify email. Click URL hits magic-link-verify.html,
// which calls /webhook/auth/magic-link-verify — that flow logs the user in
// AND flips email_verified=true via the Mark Email Verified node added
// 2026-05-29. So a successful click = verified + logged in.
const t = $('Mint Token Or Skip').item.json;
const clickUrl = 'https://crystallux.org/auth/magic-link-verify.html?token=' + encodeURIComponent(t.token);
const htmlBody = '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.55;color:#333;max-width:640px">' +
  '<h1 style="font-size:22px;font-weight:700;color:#0f172a;margin:0 0 14px;line-height:1.3;letter-spacing:-0.01em">Verify your email</h1>' +
  '<p style="color:#475569;font-size:15px;line-height:1.6;margin:0 0 24px">Click the button below to verify your email and unlock your Crystallux dashboard. The link is good for 24 hours.</p>' +
  '<p style="margin:0 0 32px"><a href="' + clickUrl + '" style="display:inline-block;padding:12px 22px;background:#0f172a;color:#fff;text-decoration:none;border-radius:8px;font-weight:600;font-size:14px">Verify my email</a></p>' +
  '<p style="font-size:13px;color:#64748b;line-height:1.6;margin:0 0 8px">Or copy this link into your browser:</p>' +
  '<p style="font-size:12px;color:#0f172a;background:#f1f5f9;padding:10px 12px;border-radius:6px;word-break:break-all;margin:0 0 24px"><a href="' + clickUrl + '" style="color:#0f172a;text-decoration:none">' + clickUrl + '</a></p>' +
  '<p style="font-size:13px;color:#94a3b8;line-height:1.6;margin:24px 0 0">If you didn\'t request this, you can safely ignore this email — no changes were made to your account.</p>' +
  '<hr style="border:none;border-top:1px solid #e5e7eb;margin:24px 0">' +
  '<p style="font-size:11px;color:#94a3b8">Crystallux Inc., Guelph, Ontario, Canada.</p>' +
  '</div>';
const textBody = 'Verify your email by clicking this link (valid 24 hours):\n\n' + clickUrl + '\n\nIf you didn\'t request this, ignore this email — no changes were made.\n\n— Crystallux';
return { json: {
  From: 'info@crystallux.org',
  To: t.email,
  Subject: 'Verify your Crystallux email',
  HtmlBody: htmlBody,
  TextBody: textBody,
  MessageStream: 'outbound',
  Tag: 'verify-email-resend',
  Metadata: { user_id: t.user_id || '', purpose: 'verify_email' }
} };
